pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract Treasury is Ownable {
    // Option 1: if the contract SHOULD hold ether, add a guarded
    // withdrawal path so funds can always leave:
    function withdraw(address payable to, uint256 amount) external onlyOwner {
        require(address(this).balance >= amount, "insufficient balance");
        (bool ok, ) = to.call{value: amount}("");
        require(ok, "withdraw failed");
    }

    // For user funds, prefer per user pull payments:
    mapping(address => uint256) public deposits;

    function deposit() external payable {
        deposits[msg.sender] += msg.value;
    }

    function withdrawMine() external {
        uint256 amount = deposits[msg.sender];
        deposits[msg.sender] = 0;
        (bool ok, ) = payable(msg.sender).call{value: amount}("");
        require(ok, "withdraw failed");
    }

    // Option 2: if the contract should NOT hold ether, remove the
    // payable ability entirely: delete receive()/fallback() and the
    // payable keyword so stray sends revert instead of getting stuck.
}
